INSERT INTO public.photos VALUES (22816, 'Av. de Marina Moreno 1973', 'Inв”ңВ®dita imagen capturada durante las "obras de embellecimiento" del paseo de Marina Moreno, que segв”ңв•‘n la moda de la в”ңВ®poca supusieron tambiв”ңВ®n su redenominaciв”ңв”Ӯn como "avenida", en tiempos en que los viales que comenzaban por "camino de...", o "paseo de..." eran considerados reliquias de un pasado a eliminar. Vivir en una avenida parece que ser que daba mв”ңГӯs prestigio social. De esta forma y al mв”ңв”Ӯdico precio de unos diez millones de pesetas, este paseo fue objeto de una intervenciв”ңв”Ӯn suntuaria en una zona bien cв”ңВ®ntrica, que ya en su momento fue tibiamente cuestionada por innecesaria. Entre otras actuaciones, se reubicв”ңв”Ӯ aquв”ңВЎ la estatua del Buen Pastor, desde el Macelo municipal. En la fotografв”ңВЎa, capturada poco antes del cruce con las calle de San Ignacio de Loyola y de Isaac Peral, terroso aspecto en obras del paseo con el fondo del moderno bloque construido en la esquina con la calle de Juan Bruil. A la derecha, traseras de la iglesia de Santa Engracia. Centra la escena una solitaria cabina telefв”ңв”Ӯnica, especialmente icв”ңв”Ӯnica tras el impactante mediometraje dirigido poco antes por Antonio Mercero.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.64820800, -0.88188800, '0101000020E6100000E083D72E6D38ECBFB680D07AF8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51599494585.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51599494585.webp', 'https://www.flickr.com/photos/zaragozaantigua/51599494585/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22867, 'Charlton Heston 1989', 'Foto: в”ңГјngel de Castro. El actor estadounidense Charlton Heston (1923-2008) visitв”ңв”Ӯ Zaragoza en febrero de 1989 para rodar localizaciones aragonesas de dos episodios de una serie de reportajes titulada "Opera Stories", en los que se situaban fragmentos operв”ңВЎsticos en los lugares en que se desarrollaba la trama. En la ciudad, estuvo en la Aljaferв”ңВЎa y visitв”ңв”Ӯ el Patio de la Infanta, momento que recoge la foto. Fuente visual: Heraldo de Aragв”ңв”Ӯn.', 1989, 1989, 1989, 'Anos 80', 'CENTRO', 41.64660300, -0.88451800, '0101000020E6100000812557B1F84DECBF6C3F19E3C3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15740641416.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15740641416.webp', 'https://www.flickr.com/photos/zaragozaantigua/15740641416/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22917, 'P.в”¬в•‘ Constituciв”ңв”Ӯn c.1984', 'Vista del paseo de la Constituciв”ңв”Ӯn, con la entrada de la calle Leв”ңв”Ӯn XIII en el centro de la imagen. Al fondo, avenida de Cesв”ңГӯreo Alierta. Fuente: Foto para postal de Comercial Josan. Cesiв”ңв”Ӯn de la familia de Josв”ңВ® Marв”ңВЎa Sanz Gonzв”ңГӯlez a Rafael Castillejo. Dataciв”ңв”Ӯn y procesado:', 1984, 1984, 1984, 'Anos 80', 'CENTRO', 41.64742100, -0.88034400, '0101000020E6100000B85A272EC72BECBF2FDFFAB0DED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27143509820.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27143509820.webp', 'https://www.flickr.com/photos/zaragozaantigua/27143509820/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22972, 'Josв”ңВ® Saramago 1992', 'El 10 de marzo de 1992, el escritor Josв”ңВ® Saramago, afiliado desde 1969 al Partido Comunista Portuguв”ңВ®s, visitв”ңв”Ӯ Zaragoza para impartir una conferencia en el Centro de Exposiciones y Congresos de Ibercaja, donde estв”ңГӯ hecha la fotografв”ңВЎa. Seis aв”ңв–’os despuв”ңВ®s le fue concedido el Premio Nobel de Literatura. Fuente: Ibercaja', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.64665700, -0.88457100, '0101000020E610000036AE7FD7674EECBF5F5D15A8C5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15014687401.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15014687401.webp', 'https://www.flickr.com/photos/zaragozaantigua/15014687401/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23679, 'Calle Bruil 1930', 'Imagen capturada desde el arranque del paseo de la Mina y centrada en el edificio del antiguo Gran Hotel Regina de la calle Bruil, habilitado en 1919 como Gran Politв”ңВ®cnica Torres o centro preparatorio para el ingreso a la Academia General Militar de Zaragoza. Tras el 18 de julio de 1936 y hasta 1939 este fue uno de los destacados escenarios de represiв”ңв”Ӯn antirrepublicana en la ciudad. Fuente visual: foto Martв”ңВЎnez, en www.bne.es/', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64830100, -0.88327500, '0101000020E610000016FBCBEEC943ECBF677BF486FBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39621373222.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39621373222.webp', 'https://www.flickr.com/photos/zaragozaantigua/39621373222/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24110, 'Calle de Juan Bruil 1936', 'Imagen capturada desde la avenida de Galв”ңГӯn y Garcв”ңВЎa Hernв”ңГӯndez, y centrada en los vehв”ңВЎculos provenientes de Mallв”ңВ®n con abastos para las tropas sublevadas en Zaragoza el 19 de julio de 1936 contra la democracia parlamentaria. Durante esas primeras semanas de conflicto era habitual la llegada de convoyes organizados desde los pueblos de la provincia que tambiв”ңВ®n secundaron la sublevaciв”ңв”Ӯn, con vв”ңВЎveres y provisiones para abastecer a la Vв”¬В¬ Divisiв”ңв”Ӯn Orgв”ңГӯnica, que militarizв”ңв”Ӯ la Gran Politв”ңВ®cnica Torres, sita en la calle de Juan Bruil nв”¬в•‘ 2, como depв”ңв”Ӯsito y almacв”ңВ®n habilitado al efecto. En la imagen, posado de vehв”ңВЎculos, malleneros y animales ante la Politв”ңВ®cnica Torres. Tras ellos, carteles con los vivas y arribas de rigor.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64829600, -0.88311100, '0101000020E6100000849CF7FF7142ECBF5610035DFBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51879128036.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51879128036.webp', 'https://www.flickr.com/photos/zaragozaantigua/51879128036/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24137, 'Feria de Muestras 1935', 'Plano de la II Feria de Muestras Aragonesa, octubre de 1935. En 1934 se celebrв”ңв”Ӯ la I Feria de Muestras Aragonesa, en la Lonja de Zaragoza. Al aв”ңв–’o siguiente se buscв”ңв”Ӯ un recinto mв”ңГӯs amplio para esa muestra comercial, y se ubicв”ңв”Ӯ en las traseras del colegio de los jesuitas (derecha), en lo que despuв”ңВ®s serв”ңВЎa el paseo Marina Moreno (abajo). Hubo que esperar hasta 1941 para que se inaugurara la siguiente, en un recinto estable junto al parque Primo de Rivera. Fuente visual: Revista Aragв”ңв”Ӯn, diciembre de 1935.', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.64751800, -0.88431200, '0101000020E610000034BBEEAD484CECBF21C9ACDEE1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20030530523.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20030530523.webp', 'https://www.flickr.com/photos/zaragozaantigua/20030530523/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24139, 'Feria de Muestras 1935', 'En 1934 se celebrв”ңв”Ӯ la I Feria de Muestras Aragonesa, en la Lonja de Zaragoza. Al aв”ңв–’o siguiente se buscв”ңв”Ӯ un recinto mв”ңГӯs amplio para esa muestra comercial, y se ubicв”ңв”Ӯ en las traseras del colegio de los jesuitas. Hubo que esperar hasta 1941 para que se inaugurara la siguiente, en un recinto estable junto al parque Primo de Rivera. En la foto, acceso a la II Feria de Muestras Aragonesa, en la avenida de Galв”ңГӯn y Garcв”ңВЎa Hernв”ңГӯndez (poco despuв”ңВ®s paseo de Marina Moreno). Al fondo, el colegio del Salvador de los padres jesuitas, en la actual plaza de Paraв”ңВЎso (a la derecha). Fuente visual: Instantв”ңГӯneas zaragozanas, CAZAR, 1982.', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.64751800, -0.88431200, '0101000020E610000034BBEEAD484CECBF21C9ACDEE1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20076691098.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20076691098.webp', 'https://www.flickr.com/photos/zaragozaantigua/20076691098/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24140, 'Expo Avв”ңВЎcola 1932', 'Imagen del "stand" de la Granja Agrв”ңВЎcola en la Exposiciв”ңв”Ӯn Nacional de Avicultura, Colombofilia y Cuniculicultura, celebrada en Zaragoza del 8 al 16 de octubre de 1932 en el patio-jardв”ңВЎn y galerв”ңВЎa cubierta del colegio del Salvador. En la imagen, aspecto del arbolado patio interior del colegio del Salvador habilitado como marco expositivo de gallinв”ңГӯceas de la Granja Agrв”ңВЎcola. Al fondo, el muro norte del colegio, recayente a la avenida de Galв”ңГӯn y Garcв”ңВЎa Hernв”ңГӯndez. Fuente visual: exposiciв”ңв”Ӯn Г”ГҮВЈLa investigaciв”ңв”Ӯn agroalimentaria en Aragв”ңв”Ӯn. Sus inicios con Rodrв”ңВЎguez AyusoГ”ГҮГҳ. Centro de Investigaciв”ңв”Ӯn y Tecnologв”ңВЎa Agroalimentaria de Aragв”ңв”Ӯn (CITA).', 1932, 1932, 1932, 'Anos 30', 'CENTRO', 41.64732000, -0.88413000, '0101000020E610000009336DFFCA4AECBFFB05BB61DBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20110630690.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20110630690.webp', 'https://www.flickr.com/photos/zaragozaantigua/20110630690/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24148, 'II Feria de Muestras 1935', 'Cartel anunciador de la II Feria de Muestras Oficial Aragonesa, cuyo diseв”ңв–’o fue ganado en concurso por Guillermo Pв”ңВ®rez Bailo, como en el certamen del aв”ңв–’o anterior. Organizado por la Cв”ңГӯmara de Comercio de Zaragoza, se celebrв”ңв”Ӯ entre el 6 y el 21 de octubre de ese aв”ңв–’o en un provisional recinto ideado por Regino Borobio, en el tramo recientemente cubierto del rв”ңВЎo Huerva entre la plaza de Paraв”ңВЎso, el colegio de los PP. Jesuitas, y la plaza de Aragв”ңв”Ӯn, y que fue denominado "avenida de Galв”ңГӯn y Garcв”ңВЎa Hernв”ңГӯndez". Por diversas circunstancias, hasta 1941 no habrв”ңВЎa mв”ңГӯs ferias de muestras, que en 1943 recibieron la denominaciв”ңв”Ӯn de "nacional". Fuente visual: www.todocoleccion.net/', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.64811300, -0.88292800, '0101000020E610000043209738F240ECBF658EE55DF5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25613549536.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25613549536.webp', 'https://www.flickr.com/photos/zaragozaantigua/25613549536/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24149, 'Expo Avв”ңВЎcola 1932', 'Del 8 al 16 de octubre de 1932 tuvo lugar en Zaragoza la "Exposiciв”ңв”Ӯn Nacional de Avicultura, Colombofilia y Cuniculicultura", organizada por la Asociaciв”ңв”Ӯn Avв”ңВЎcola Aragonesa con el respaldo, entre otros, del Ayuntamiento, y la Universidad. Paralelamente, se celebrв”ңв”Ӯ la Asamblea de Avicultores con carв”ңГӯcter estatal. La exposiciв”ңв”Ӯn tuvo como escenario el patio-jardв”ңВЎn y galerв”ңВЎa cubierta del colegio del Salvador, contв”ңв”Ӯ con la muestra de mв”ңГӯs de 500 selectos ejemplares de gallinв”ңГӯceas, palmв”ңВЎpedas, palomas, y conejos, ademв”ңГӯs de materiales, alimentos y accesorios relacionados con el sector. Al final, el jurado de la Exposiciв”ңв”Ӯn concediв”ңв”Ӯ varios premios de honor entre lo mв”ңГӯs destacado de las diversas categorв”ңВЎas a concurso. La Asamblea, y las conferencias de la Exposiciв”ңв”Ӯn, se celebraron en dependencias de la cercana Facultad de Medicina. En la imagen, aspecto del arbolado patio interior del colegio del Salvador habilitado como marco expositivo de lotes de gallinв”ңГӯceas. Al fondo, el muro norte del colegio, recayente a la avenida de Galв”ңГӯn y Garcв”ңВЎa Hernв”ңГӯndez. Fuente: "Mundo Avв”ңВЎcola", Barcelona, 1932.', 1932, 1932, 1932, 'Anos 30', 'CENTRO', 41.64732000, -0.88413000, '0101000020E610000009336DFFCA4AECBFFB05BB61DBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25789855713.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25789855713.webp', 'https://www.flickr.com/photos/zaragozaantigua/25789855713/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24164, 'Pl. de Castelar c.1923', 'Imagen de la plaza de Castelar cuando en ella se ubicaban las ferias y atracciones durante las fiestas mayores para divertimento de chicos y chacos. La captura se ha realizado en la zona sur de la plaza, sobre la despejada manzana aв”ңв•‘n sin urbanizar de la prolongaciв”ңв”Ӯn de la calle de Joaquв”ңВЎn Costa, donde pocos aв”ңв–’os despuв”ңВ®s se barajarв”ңВЎa temporalmente la construcciв”ңв”Ӯn del nuevo edificio del Ayuntamiento de la ciudad. Al fondo, entre atracciones, vista parcial del ala sur del Museo Provincial.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.64817400, -0.87986200, '0101000020E6100000E7C75F5AD427ECBF0A0F9A5DF7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45616915291.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45616915291.webp', 'https://www.flickr.com/photos/zaragozaantigua/45616915291/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24299, 'Gran Casino 1908', 'Foto: Ignacio Coyne, 1908. Gran Casino de la Exposiciв”ңв”Ӯn Hispano Francesa de Zaragoza. Fuente: dara.aragon.es/', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64819800, -0.88125600, '0101000020E6100000BCEB6CC83F33ECBF93AAED26F8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18990276864.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18990276864.webp', 'https://www.flickr.com/photos/zaragozaantigua/18990276864/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24300, 'Pabellв”ңв”Ӯn de Reales Patrimonios 1908', 'Foto: Ignacio Coyne, 1908. Pabellв”ңв”Ӯn de los Reales Patrimonios, o posesiones de la Corona de Espaв”ңв–’a. Estaba adosado al interior de la tapia de la Exposiciв”ңв”Ӯn Hispano Francesa de Zaragoza. Fuente. в”ңГјlbum oficial de la Exposiciв”ңв”Ӯn Hispano-Francesa, 1908.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64783800, -0.88019400, '0101000020E61000006555849B8C2AECBF938D075BECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18995465313.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18995465313.webp', 'https://www.flickr.com/photos/zaragozaantigua/18995465313/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24329, 'Pl. de Castelar 1930', 'Imagen capturada en la plaza de Castelar desde el cruce de las calles de Costa y del Arquitecto Magdalena, para ilustrar el gran solar en el que estaba prevista la construcciв”ңв”Ӯn de la nueva Casa del Ayuntamiento. Al fondo, de fachada, los nuevos bloques de vivienda de la calle Sancho y Gil. El в”ңв•‘ltimo de ellos, con el nв”¬в•‘ 13, habв”ңВЎa sido diseв”ңв–’ado por el arquitecto Francisco Albiв”ңв–’ana. Tras ellos estaba prevista la construcciв”ңв”Ӯn de la Casa del Pueblo de la UGT, proyecto estancado y no realizado. A la izquierda, un provisional quiosco frente al Museo provincial. A la derecha, alboleda del paseo de la Mina, junto al punto lв”ңВЎmite donde terminaba el cubrimiento del rв”ңВЎo Huerva. Fuente visual: www.mecd.gob.es/.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64817400, -0.87986200, '0101000020E6100000E7C75F5AD427ECBF0A0F9A5DF7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34471873023.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34471873023.webp', 'https://www.flickr.com/photos/zaragozaantigua/34471873023/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24341, 'Memoria hв”ңВ®roes c.1850', 'Dibujo firmado por el arquitecto Matв”ңВЎas Laviв”ңв–’a Blasco con el tв”ңВЎtulo "proyecto de un monumento para perpetuar la memoria de los hв”ңВ®roes de 1808 con arreglo a lo acordado por las Cortes de Cв”ңГӯdiz". Representa de forma idealista una localizaciв”ңв”Ӯn de la periferia urbana centrada en una estructura de planta cuadrada con un pв”ңв”Ӯrtico y escaleras de acceso en cada uno de los lados, del que emerge un espacio abovedado apoyado en un tambor octogonal y rematado por un alegв”ңв”Ӯrico bulto redondo. La influencia de los aв”ңв–’os de estancia del autor en Roma aprendiendo el oficio se refleja tanto en las formas del edificio como en las vestimentas propias de la antigв”ңв•қedad clв”ңГӯsica romana que portan las figuras que pasean por el entorno. Las ruinas del fondo a la izquierda podrв”ңВЎan estar inspiradas de alguna forma en las del monasterio de santa Engracia. Este proyecto no fue realizado.', 1850, 1850, 1850, 'Siglo XIX', 'CENTRO', 41.64798300, -0.88417400, '0101000020E6100000F226BF45274BECBF97AE601BF1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52244985479.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52244985479.webp', 'https://www.flickr.com/photos/zaragozaantigua/52244985479/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24458, 'Fundiciв”ңв”Ӯn Martв”ңВЎn Rodв”ңв”Ӯn 1885', 'Dibujo de cabecera de factura de la empresa "Grandes talleres de fundiciв”ңв”Ӯn y construcciв”ңв”Ӯn de mв”ңГӯquinas de Martв”ңВЎn Rodв”ңв”Ӯn y Hermano"; en 1885. Estaba situada en el Paseo de las Damas, tramo comprendido entre las actuales calles de San Ignacio de Loyola (antigua de Rodв”ңв”Ӯn) y Leв”ңв”Ӯn XIII. Fuente: Mв”¬В¬ Pilar Biel Ibв”ңГӯв”ңв–’ez, Zaragoza y la industrializaciв”ңв”Ӯn: la arquitectura industrial 1875-1936, IFC, 2004.', 1885, 1885, 1885, 'Siglo XIX', 'CENTRO', 41.64578400, -0.88427200, '0101000020E6100000A69718CBF44BECBFD923D40CA9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19626693852.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19626693852.webp', 'https://www.flickr.com/photos/zaragozaantigua/19626693852/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24715, 'P.в”¬в•‘ de los Plв”ңГӯtanos c.1953', 'El paseo de los Plв”ңГӯtanos, llamado asв”ңВЎ por los в”ңГӯrboles que lo flanqueaban, comenzaba en la avenida de Marina Moreno y llegaba hasta el camino de las Torres. La actual calle de Francisco de Vitoria coincide aproximadamente con parte del trazado del antiguo camino o paseo de los Plв”ңГӯtanos. Fuente: "Zaragoza. Instantв”ңГӯneas grises", CAZAR, 1972.', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.64662000, -0.88015800, '0101000020E610000032022A1C412AECBF4278B471C4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15409559845.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15409559845.webp', 'https://www.flickr.com/photos/zaragozaantigua/15409559845/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24716, 'Casa Sindical 1945', 'El Delegado nacional de Sindicatos, Fermв”ңВЎn Sanz Olmo, inaugura la Casa Sindical, el nuevo edificio de la Delegaciв”ңв”Ӯn Provincial de Sindicatos, en la avenida de Marina Moreno 12, esquina con la nueva calle de San Ignacio de Loyola. Fuente: Foto Lozano, Agencia EFE', 1945, 1945, 1945, 'Anos 40', 'CENTRO', 41.64781500, -0.88258600, '0101000020E6100000E109BDFE243EECBFDB6D179AEBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21145262544.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21145262544.webp', 'https://www.flickr.com/photos/zaragozaantigua/21145262544/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24717, 'P.в”¬в•‘ de los Plв”ңГӯtanos 1948', 'Imagen en altura, desde el nв”¬в•‘ 9 de la nueva calle Madre Vedruna, del entorno del antiguo camino de los Plв”ңГӯtanos entre Marina Moreno, el nuevo vial denominado S. Ignacio de Loyola (izquierda), y la propia Madre Vedruna. Se trataba de uno de los espacios entre lo agrв”ңВЎcola, industrial y residencial difuso que, hasta ese momento, la expansiв”ңв”Ӯn urbana habв”ңВЎa dejado atrв”ңГӯs, para dirigir su crecimiento en otras direcciones. En el momento de realizar la imagen, la urbanizaciв”ңв”Ӯn de la zona, y la construcciв”ңв”Ӯn de los primeros bloques, como los de la izquierda, seв”ңв–’alaba el camino de transformaciв”ңв”Ӯn radical que este lugar conocerв”ңВЎa a partir de ese momento, si bien no se completarв”ңВЎa hasta bien entrados los aв”ңв–’os 70, cuando lo que hasta entonces habв”ңВЎan sido apenas terrenos de labor, una densa red de acequias y riegos, caminos de tierra, y unas parcelas vertebradas por el camino de los Plв”ңГӯtanos y el peculiar callejв”ңв”Ӯn de Rodв”ңв”Ӯn, se configurв”ңв”Ӯ como una selecta y muy exclusiva zona habitacional. En la imagen, al fondo, los bloques de la avenida de Marina Moreno recayentes a la plaza de Josв”ңВ® Antonio, con la calle Mariano Escar como ingreso a la misma. Entre ellos destaca, posiblemente, una de las pocas imв”ңГӯgenes de la antigua casa unifamiliar proyectada para Marcos Samper por el arquitecto Mariano Blasco y Taula, luego desaparecida por provinciana. Muy cerca y en la margen derecha del rв”ңВЎo Huerva estaba ubicada la fв”ңГӯbrica de harinas de la que era propietario. A la izquierda, el reciente edificio de la Delegaciв”ңв”Ӯn Provincial de Sindicatos, y el pionero bloque del 12 de Marina Moreno, en lo que hasta entonces habв”ңВЎa sido el principio del camino de los Plв”ңГӯtanos. Las naves se corresponden a los talleres industriales que, como muebles Loscertales, allв”ңВЎ estuvieron ubicados. Fuente visual: Archivo Construcciones y Auxiliar de Ferrocarriles (DARA-AHPZ).', 1948, 1948, 1948, 'Anos 40', 'CENTRO', 41.64711900, -0.88174800, '0101000020E61000007007EA944737ECBF64CF9ECBD4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23642295589.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23642295589.webp', 'https://www.flickr.com/photos/zaragozaantigua/23642295589/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24718, 'Av. Marina Moreno c.1951', 'Vista de la avenida de Marina Moreno, con las traseras de la iglesia de Santa Engracia a la derecha. Al fondo, la calle de Juan Bruil. A la izquierda, edificio del arranque de la nueva calle de San Ignacio de Loyola que confrontaba conla Casa Sindical. Fuente: Colecciв”ңв”Ӯn particular.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64824500, -0.88256600, '0101000020E61000001AF8510DFB3DECBFD46531B1F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32413352913.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32413352913.webp', 'https://www.flickr.com/photos/zaragozaantigua/32413352913/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24719, 'C.в”¬в•‘ de los Plв”ңГӯtanos 1931', 'Imagen de los restos del frontв”ңв”Ӯn del camino de los Plв”ңГӯtanos, que se vino abajo tras el notable temporal de viento y lluvias que sacudiв”ңв”Ӯ a la ciudad. Este frontв”ңв”Ӯn estaba ubicado al principio del paseo, junto a los talleres de muebles de Luciano Loscertales. Al fondo, la calle de Juan Bruil, con el chaflanero y antiguo Hotel Regina, reconvertido en Academia Preparatoria Militar. Fuente visual: foto Marв”ңВЎn Chivite, en diario "Ahora".', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.64778500, -0.88195200, '0101000020E61000008F899466F338ECBF70EB6E9EEAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32821167385.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32821167385.webp', 'https://www.flickr.com/photos/zaragozaantigua/32821167385/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24720, 'Colegio del Salvador c.1951', 'Aв”ңВ®rea visual centrada en la rotunda estructura del colegio del Salvador, entre el despejado paseo de Marina Moreno (izquierda) y el callejв”ңв”Ӯn de Rodв”ңв”Ӯn (derecha). Al fondo, viviendas de la calle del arquitecto Yarza y de Madre Vedruna, ademв”ңГӯs de algunas naves del antiguo paseo de los Plв”ңГӯtanos. Fuente visual: A.A.A. Jesuitas Zaragoza', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64693500, -0.88461200, '0101000020E6100000DAC534D3BD4EECBFA2D11DC4CED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34418405152.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34418405152.webp', 'https://www.flickr.com/photos/zaragozaantigua/34418405152/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24721, 'C.в”¬в•‘ de los Plв”ңГӯtanos 1931', 'Imagen capturada en la gran finca de Yarza del camino de los Plв”ңГӯtanos, marco incomparable para la celebraciв”ңв”Ӯn de la verbena de la Asociaciв”ңв”Ӯn de la Prensa de ese aв”ңв–’o. Posan un grupo de seв”ңв–’oritas asistentes, en un espacio preparado para la ocasiв”ңв”Ӯn por diversas brigadas municipales que se encargaron del ornato y la iluminaciв”ңв”Ӯn de un evento por el que pasaron miles de personas. Este feraz entorno de la ciudad, en pleno centro, fue muy remodelado tiempo despuв”ңВ®s mediante una progresiva urbanizaciв”ңв”Ӯn que la fue consolidando como una de las zonas residenciales mв”ңГӯs selectas de la moderna Zaragoza. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.64755200, -0.88277800, '0101000020E6100000EF1AF4A5B73FECBFCD3AE3FBE2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35343290086.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35343290086.webp', 'https://www.flickr.com/photos/zaragozaantigua/35343290086/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24722, 'Av. de Marina Moreno 1939', 'Imagen del chaflanero y nuevo edificio de vivienda para casas de renta ubicado en el nв”¬в•‘ 8 de la avenida de Galв”ңГӯn y Garcв”ңВЎa Hernв”ңГӯndez (desde 1938, de Marina Moreno), con diseв”ңв–’o de Josв”ңВ® de Yarza Garcв”ңВЎa junto a Alejandro Allanegui Fв”ңВ®lez. Su construcciв”ңв”Ӯn se iniciв”ңв”Ӯ en 1935, y la guerra de 1936-39 retrasв”ңв”Ӯ su finalizaciв”ңв”Ӯn hasta 1939. Supuso el comienzo de la urbanizaciв”ңв”Ӯn de la antigua y gran torre "Campos Elв”ңВЎseos" de la familia Yarza, como pionera inversiв”ңв”Ӯn inmobiliaria en una zona residencial muy cв”ңВ®ntrica y orientada a familias de alto poder adquisitivo. La captura visual se ha realizado desde la referida avenida, sobre un tramo cubierto del rв”ңВЎo Huerva. A la derecha, el antiguo muro que delimitaba el lв”ңВЎmite mв”ңГӯs septentrional del gran colegio de El Salvador, y que poco despuв”ңВ®s serв”ңВЎa derribado para abrir aquв”ңВЎ un nuevo vial que conectarв”ңГӯ con el callejв”ңв”Ӯn de Rodв”ңв”Ӯn y con el camino de los Plв”ңГӯtanos a travв”ңВ®s de la nueva calle de San Ignacio de Loyola. Aв”ңв–’os despuв”ңВ®s, el vial de la imagen serв”ңГӯ denominado calle del Arquitecto Yarza. Fuente visual: arch. J. de Yarza', 1939, 1939, 1939, 'Anos 30', 'CENTRO', 41.64766500, -0.88356100, '0101000020E61000007EACE0B72146ECBFC6E1CCAFE6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35542918031.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35542918031.webp', 'https://www.flickr.com/photos/zaragozaantigua/35542918031/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24723, 'Calle Nueva de las Torres 1932', 'Imagen centrada en el nв”¬в•‘ 205 de la calle Nueva de las Torres, inmediata al camino de las Torres o del Gas (hacia la derecha, fuera de plano), con motivo del hallazgo de armas y explosivos por parte de efectivos del Cuerpo de Seguridad y Asalto. Otros explosivos fueron hallados en el huerto del cercano nв”¬в•‘ 209 de la misma calle (hacia la izquierda). Este vial surgiв”ңв”Ӯ a finales del siglo XIX tras la parcelaciв”ңв”Ӯn y urbanizaciв”ңв”Ӯn particular de la antigua Torre de Rubio. En 1953 fue redenominado como calle del General Sueiro en homenaje al africanista y golpista teniente general homв”ңв”Ӯnimo. En 2009 la calle recibiв”ңв”Ӯ su actual denominaciв”ңв”Ӯn: Josв”ңВ® Marв”ңВЎa Lacarra y de Miguel. Los edificios de la imagen ya habв”ңВЎan sido derribados con bastante antelaciв”ңв”Ӯn, sustituidos por otros mв”ңГӯs acordes a la categorв”ңВЎa socioeconв”ңв”Ӯmica de la zona. Fuente visual: www.mecd.gob.es/.', 1932, 1932, 1932, 'Anos 30', 'CENTRO', 41.64358800, -0.88082700, '0101000020E6100000A0E1CD1ABC2FECBF8D0C721761D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35548645942.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35548645942.webp', 'https://www.flickr.com/photos/zaragozaantigua/35548645942/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24724, 'P.в”¬в•‘ de Marina Moreno c.1951', 'Desde la altura del Hotel Centenario, antes sede la academia Politв”ңВ®cnica Torres, una vista muy interesante, con varios puntos de singular interв”ңВ®s, del paseo de Marina Moreno que alcanza al fondo al colegio de los Corazonistas del paseo de la Mina, por encima del cual incluso emerge la torre del internado de las Hermanitas de los Ancianos Desamparados. A la derecha, el emboque a la calle de San Ignacio de Loyola. flanqueado por la Delegaciв”ңв”Ӯn Provincial de Sindicatos, y un poco mв”ңГӯs adelante restos edilicios del paseo de los Plв”ңГӯtanos en proceso de extinciв”ңв”Ӯn. Vertebra la escena el urbanizado paseo, cuyos jardines en proceso de modelado alcanzan hasta donde llegв”ңв”Ӯ el cubrimiento del rв”ңВЎo Huerva, a la altura de la calle de Mefisto. Los aв”ңВ®reos cables soportados por postes de hormigв”ңв”Ӯn que jalonan el lado de los impares, desde el primer tв”ңВ®rmino inmediato y hasta el paseo de la Mina, seв”ңв–’alan el paso del trolebв”ңв•‘s de la novв”ңВЎsima lв”ңВЎnea del Terminillo, que originalmente en su recorrido de regreso transitaban el paseo de Marina Moreno hasta la calle de Isaac Peral, por donde se internaban hasta la de Jerв”ңв”Ӯnimo Zurita para dar la vuelta y acceder a la terminal de inicio de ruta ubicada en el paseo de la Independencia, que luego fue trasladada a la plaza de Santa Engracia. El resto del tendido que al fondo del paseo de la Mina se prolongaba hasta la plaza de San Miguel era utilizado para el acceso a la ruta que por la calle de Miguel Servet conducв”ңВЎa y provenв”ңВЎa de las cocheras. A la izquierda, tramo de los impares del paseo de Marina Moreno comprendido entre la calle de Don Hernando de Aragв”ңв”Ӯn, Isaac Peral, Mariano Escar, y Mefisto, con el desarrollo edilicio del momento. En el centro de la escena, posiblemente una de las pocas imв”ңГӯgenes, siquiera parciales como esta, de la antigua casa unifamiliar proyectada para el industrial Marcos Samper por el arquitecto Mariano Blasco y Taula, luego desaparecida por provinciana. Muy cerca y en la margen derecha del rв”ңВЎo Huerva estaba ubicada la fв”ңГӯbri', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64822400, -0.88218900, '0101000020E61000009D82FC6CE43AECBFBC3D0801F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50097711728.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50097711728.webp', 'https://www.flickr.com/photos/zaragozaantigua/50097711728/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24725, 'P.в”¬в•‘ de Marina Moreno c.1952', 'Imagen capturada en el paseo de Marina Moreno, con la calle de Agustina Simв”ңв”Ӯn a la espalda, y orientado el objetivo hacia la reciente manzana urbanizada entre las calles del Arquitecto Yarza y de San Ignacio de Loyola. La foto casi se centra en el pionero inmueble del nв”¬в•‘ 8 del paseo, proyectado por los arquitectos Josв”ңВ® de Yarza Garcв”ңВЎa y Alejandro Allanegui Fв”ңВ®lez, cuya construcciв”ңв”Ӯn se iniciв”ңв”Ӯ en 1935, aunque la guerra de 1936-39 retrasв”ңв”Ӯ su finalizaciв”ңв”Ӯn hasta 1939. Supuso el comienzo de la urbanizaciв”ңв”Ӯn de la antigua y gran torre "Campos Elв”ңВЎseos" de la familia Yarza, y de la gran zona delimitada entre el paseo de las Damas y el de Marina Moreno. Al fondo, provisional vacв”ңВЎo edilicio en el entorno rururbano del antiguo callejв”ңв”Ӯn de Rodв”ңв”Ӯn y del paseo de los Plв”ңГӯtanos, donde en la imagen incluso se intuye un jinete a caballo. A la derecha, в”ңГӯrboles de los patios traseros del colegio del Salvador.', 1952, 1952, 1952, 'Anos 50', 'CENTRO', 41.64779100, -0.88383000, '0101000020E6100000632827DA5548ECBF52D2C3D0EAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50800408278.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50800408278.webp', 'https://www.flickr.com/photos/zaragozaantigua/50800408278/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24726, 'Calle de Madre Vedruna, 1948', 'Imagen capturada desde la altura del inmueble del nв”¬в•‘ 9 de la calle de Madre Vedruna, con aspecto de cв”ңв”Ӯmo estaba empezando a cambiar la zona vertebrada por el callejв”ңв”Ӯn de Rodв”ңв”Ӯn y el paseo de los Plв”ңГӯtanos. A la izquierda, la calle del Arquitecto Yarza, y en el centro de la escena la nueva manzana delimitada ademв”ңГӯs por la nueva calle de San Ignacio de Loyola y el paseo de Marina Moreno. En primer tв”ңВ®rmino, el callejв”ңв”Ӯn de Rodв”ңв”Ӯn jalona un espacio entre lo agrв”ңВЎcola, industrial y residencial difuso. En el momento de realizar la imagen, la urbanizaciв”ңв”Ӯn de la zona, y la construcciв”ңв”Ӯn de los primeros bloques seв”ңв–’alaba el camino de transformaciв”ңв”Ӯn radical que este lugar conocerв”ңВЎa a partir de ese momento, si bien no se completarв”ңВЎa hasta bien entrados los aв”ңв–’os 70, cuando lo que hasta entonces habв”ңВЎan sido apenas terrenos de labor, una densa red de acequias y riegos, caminos de tierra, y unas parcelas vertebradas por el camino de los Plв”ңГӯtanos y el callejв”ңв”Ӯn de Rodв”ңв”Ӯn, se configurв”ңв”Ӯ como una selecta y muy exclusiva zona habitacional.', 1948, 1948, 1948, 'Anos 40', 'CENTRO', 41.64714100, -0.88258600, '0101000020E6100000E109BDFE243EECBF4B732B84D5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50807141043.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50807141043.webp', 'https://www.flickr.com/photos/zaragozaantigua/50807141043/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24727, 'Vista Expo 1908', 'Imagen capturada posiblemente desde la altura del colegio del Salvador y orientada en direcciв”ңв”Ӯn hacia el luminoso recinto de la Exposiciв”ңв”Ӯn Hispano-Francesa de 1908, donde la antigua huerta de Santa Engracia. En primer tв”ңВ®rmino, el feraz entorno de la huerta colegial y de las vecinas torres de Antonio Ardid y de los Yarza, estas dos limitando con el paseo de los Plв”ңГӯtanos y sus talleres fabriles hacia la derecha. Al otro lado de la ribera del rв”ңВЎo Huerva, el recinto de la exposiciв”ңв”Ӯn donde destacan por su altura el Palacio de los Museos y la torrecilla del Pabellв”ңв”Ӯn Mariano. El telв”ңв”Ӯn de fondo urbano aparece interrumpido por la emergencia de la torre de la iglesia de San Miguel de los Navarros, y aparentemente juntas, la de San Carlos Borromeo y la de Santa Marв”ңВЎa Magdalena.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64820800, -0.88067600, '0101000020E610000036E84B6F7F2EECBFB680D07AF8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51568870129.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51568870129.webp', 'https://www.flickr.com/photos/zaragozaantigua/51568870129/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24728, 'Pв”¬в•‘. de las Damas 1909', 'Imagen capturada durante la ceremonia de bendiciв”ңв”Ӯn del solar y de la primera piedra de la nueva iglesia, capilla y noviciado de las RR. Madres Oblatas del Santв”ңВЎsimo Redentor, asв”ңВЎ como la inauguraciв”ңв”Ӯn del edificio de los locales para la enfermerв”ңВЎa terminado poco antes y que en la foto queda justo tras el tabernв”ңГӯculo decorado con motivos vegetales. La escena tiene lugar en el patio de este convento inaugurado en 1887 en la antigua Torre de Ponte en el paseo de las Damas, antes paseo de Sasera. A la izquierda destaca el arzobispo Juan Soldevila durante la ceremonia. En primer tв”ңВ®rmino, autoridades locales y entre ellas, el gobernador civil Sr. Tejв”ңв”Ӯn y el alcalde Sr. Fleta. Ademв”ңГӯs, la Madre General del Instituto de Oblatas, los directores espirituales de la Comunidad, las asiladas ("en su mayorв”ңВЎa muchachas abandonadas y de vida licenciosa", segв”ңв•‘n el lenguaje de la в”ңВ®poca utilizado en publicaciones catв”ңв”Ӯlicas sometidas a la censurada eclesiв”ңГӯstica), la Junta de Damas recaudatoria de fondos para la obra, y otros invitados "de las clases mв”ңГӯs elevadas de la sociedad" (sic) zaragozana. Al fondo y desde la distancia, la Comunidad de las Oblatas observa la ceremonia junto al edificio conventual.', 1909, 1909, 1909, 'Anos 1900', 'CENTRO', 41.64357400, -0.88263900, '0101000020E61000009692E524943EECBF284701A260D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53245666157.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53245666157.webp', 'https://www.flickr.com/photos/zaragozaantigua/53245666157/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24887, 'El Buen Pastor 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 27/02/1974. Remodelaciв”ңв”Ӯn del Paseo de marina Moreno, que incluв”ңВЎa la instalaciв”ңв”Ӯn de la estatua "El Buen Pastor", trasvasada desde su original ubicaciв”ңв”Ӯn en el patio del macelo de Miguel Servet. La estatua sв”ңв”Ӯlo regresarв”ңВЎa cuando el Matadero se hubiera convertido en Centro Cв”ңВЎvico Salvador Allende, y ya en el siglo XXI. Para ello tendrв”ңГӯ que sufrir una agresiв”ңв”Ӯn que la deje demediada.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.64736600, -0.88024100, '0101000020E61000009225732CEF2AECBF6B459BE3DCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14947312432.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14947312432.webp', 'https://www.flickr.com/photos/zaragozaantigua/14947312432/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24918, 'Paseo Constituciв”ңв”Ӯn 2005', 'Foto: Esther Casas. Obras de desmantelamiento de la fuente del Buen Pastor en el paseo de la Constituciв”ңв”Ӯn (al fondo, calle de Leв”ңв”Ӯn XIII). Estuvo allв”ңВЎ desde 1974 y en 2005 fue trasladada a su ubicaciв”ңв”Ӯn original, en el Matadero, entonces ya Centro Cв”ңВЎvico Salvador Allende. Fuente: Heraldo de Aragв”ңв”Ӯn.', 2005, 2005, 2005, 'Siglo XXI', 'CENTRO', 41.64738700, -0.88024900, '0101000020E610000047C66AF3FF2AECBF836DC493DDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31684725196.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31684725196.webp', 'https://www.flickr.com/photos/zaragozaantigua/31684725196/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25020, 'Calle del Arte 1907', 'El primer taller del escultor muelino Dionisio Lasuв”ңВ®n estuvo ubicado, en 1881, en la calle de los Huertos, hasta que se diseв”ңв–’в”ңв”Ӯ su propia casa-taller en un vial particular y perpendicular al Paseo de Torrero, que fue bautizado por el propio escultor como Calle del Arte. El edificio, en estilo modernista, tenв”ңВЎa el nв”ңв•‘mero 15, y estaba al final de la calle, que no tenв”ңВЎa salida, cerca del enlace con la calle del Progreso. Fue derribado cuando comenzaba la dв”ңВ®cada de los aв”ңв–’os 60, tal vez porque era una casa demasiado insв”ңв”Ӯlita para esta ciudad. En la imagen, la nuera de Dionisio se asoma por la ventana, y es capturada inopinadamente. Fuente visual: Foto Freudenthal.', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64307300, -0.88417800, '0101000020E61000004DF73AA92F4BECBF66F84F3750D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15349816560.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15349816560.webp', 'https://www.flickr.com/photos/zaragozaantigua/15349816560/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25028, 'Dionisio Lasuв”ңВ®n 1907', 'Imagen del escultor Dionisio Lasuв”ңВ®n Ferrer, su hijo, y su nuera, posando en su casa-taller de la calle del Arte, un excepcional edificio modernista diseв”ңв–’ado por el propio Lasuв”ңВ®n, y que fue derrumbado cuando comenzaba la dв”ңВ®cada de los aв”ңв–’os 60. Lasuв”ңВ®n padre posa junto al modelado en arcilla de la sedente alegorв”ңВЎa de la "Arqueologв”ңВЎa", de 190 centв”ңВЎmetros de altura, identificada con los atributos de un libro, unas medallas y una figurilla del antiguo Egipto (tal vez un ushebti votivo). Esta obra estaba destinada a decorar la fachada principal del nuevo edificio denominado provisionalmente "Palacio de Museos", como parte de la Exposiciв”ңв”Ӯn Hispano-Francesa de 1908 en la antigua huerta de Santa Engracia. Esta escultura, en su prevista ubicaciв”ңв”Ӯn palaciega, estarв”ңВЎa cobijada bajo templete adosado, a la izquierda de la fachada principal de ingreso, entre los medallones con los retratos en altorrelieve de Damiв”ңГӯn Forment, y de Francisco Goya, esculpidos en el taller de Carlos Palao y Pascual Salaberri. A su derecha, su hijo modela un busto de su mujer, que posa para la ocasiв”ңв”Ӯn. Fuente: Foto Freudenthal.', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64307300, -0.88417800, '0101000020E61000004DF73AA92F4BECBF66F84F3750D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24050507374.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24050507374.webp', 'https://www.flickr.com/photos/zaragozaantigua/24050507374/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25038, 'Calle del Arte 1936', 'Imagen de la antigua calle del Arte, cuando terminaba bruscamente a la altura del nв”¬в•‘ 27, con una valla tras la que extendв”ңВЎan huertos hasta el paseo de Sasera y el camino de las Torres, al fondo. La captura se ha realizado desde el arranque de la calle del Progreso (a la derecha, fuera de plano). A la izquierda, y luminosa, la fachada de la casa-taller que fuera del escultor Dionisio Lasuв”ңВ®n, aв”ңв•‘n en pie, un poco antes del desemboque de la calle del doctor Casas. Casi enfrente, a la derecha, y en penumbra, la casa nв”¬в•‘ 16, diseв”ңв–’ada recientemente por Alberto Huerta Marв”ңВЎn, que perdura, como los nв”ңв•‘meros 20, 25 y 27. El resto, es de nueva planta. Fuente visual: diario "El Noticiero". Archivo Josв”ңВ® Marв”ңВЎa Ballestв”ңВЎn Miguel.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64307300, -0.88417800, '0101000020E61000004DF73AA92F4BECBF66F84F3750D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32478284526.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32478284526.webp', 'https://www.flickr.com/photos/zaragozaantigua/32478284526/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25046, 'Colegio El Salvador c.1900', 'Imagen capturada desde cierta altura, posiblemente desde el cuartel de Santa Engracia, con una vista de las traseras del gran colegio El Salvador, con entrada principal desde el paseo de Sagasta, cuya planta en forma de "U" se manifiesta bien visible. Por encima sobresale levemente la estructura del colegio del Sagrado Corazв”ңв”Ӯn. En primer tв”ңВ®rmino, muros delimitadores de los jardines traseros del hotelito del nв”¬в•‘ 1 de la plaza de Aragв”ңв”Ӯn, y de la trinchera que encajonaba el cauce al aire del rв”ңВЎo Huerva. A la izquierda, vista parcial de la torre de los Campos Elв”ңВЎseos y arranque del paseo de los Plв”ңГӯtanos.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64753400, -0.88311100, '0101000020E6100000849CF7FF7142ECBF2786E464E2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49909332956.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49909332956.webp', 'https://www.flickr.com/photos/zaragozaantigua/49909332956/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25047, 'Colegio El Salvador 1908', 'Imagen capturada desde cierta altura de la fachada principal del gran colegio El Salvador, precedido por la ajardinada zona de ingreso desde el paseo de Sagasta. A la derecha de la escena, inmediato y fuera de plano, el callejв”ңв”Ӯn de Rodв”ңв”Ӯn entre el colegio y la homв”ңв”Ӯnima fundiciв”ңв”Ӯn.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64671600, -0.88442000, '0101000020E6100000CCB4FD2B2B4DECBF64E60297C7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49912056238.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49912056238.webp', 'https://www.flickr.com/photos/zaragozaantigua/49912056238/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25099, 'Saramago 1990', 'El escritor portuguв”ңВ®s Josв”ңВ® Saramago (1922-2010), Premio Nobel de Literatura en 1998, posa junto a Ramв”ңв”Ӯn Acв”ңВЎn, coordinador del ciclo pedagв”ңв”Ӯgico "Invitaciв”ңв”Ӯn a la lectura" del Ministerio de Educaciв”ңв”Ӯn y Ciencia, celebrado en la sede central de Ibercaja. Es la primera de las tres visitas de Saramago a la ciudad. La toma se ha realizado junto a la entrada del aparcamiento de la calle de San Ignacio de Loyola, con el edificio de Ibercaja al fondo.', 1990, 1990, 1990, 'Anos 90', 'CENTRO', 41.64679300, -0.88405600, '0101000020E610000076A4FACE2F4AECBF1024EF1CCAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49128020041.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49128020041.webp', 'https://www.flickr.com/photos/zaragozaantigua/49128020041/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25229, 'P.в”¬в•‘ de Marina Moreno c.1960', 'Imagen capturada desde la altura inmueble del nв”¬в•‘ 8 del paseo de Marina Moreno. A la izquierda e inmediata, fachada de la Residencia Universitaria de los padres jesuitas. A la derecha, traseras al paseo de los "hotelitos" de la plaza de Aragв”ңв”Ӯn correspondientes a los nв”ңв•‘meros 4 a 8, entre los que emerge el edificio de Capitanв”ңВЎa General y el moderno inmueble chaflanero con la calle del Doctor Cerrada. Hacia el fondo y tras la plaza de Basilio Paraв”ңВЎso, el arranque del paseo de Calvo Sotelo flanqueado por el Edificio Elв”ңВЎseos y la Facultad de Medicina y Ciencias.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.64770300, -0.88388400, '0101000020E61000002FA52E19C748ECBFB34291EEE7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49506727006.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49506727006.webp', 'https://www.flickr.com/photos/zaragozaantigua/49506727006/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25580, 'Marina Moreno 1960', 'Imagen en altura del Paseo de Marina Moreno, hasta el arranque del Paseo de la Mina. A la izquierda, los edificios de la entrada a la calle Mefisto y a la plaza de Josв”ңВ® Antonio. Al fondo, el antiguo edificio del colegio del Sagrado Corazв”ңв”Ӯn, junto al Huerva. Mв”ңГӯs al fondo, a la izquierda, visual de las instalaciones de la fв”ңГӯbrica de Gas del Camino de las Torres. Fuente: Archivo Municipal. Gerardo Sancho Ramo. 1960.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.64720100, -0.88015600, '0101000020E6100000051A6CEA3C2AECBF21787C7BD7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15710838161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15710838161.webp', 'https://www.flickr.com/photos/zaragozaantigua/15710838161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25902, 'P.в”¬в•‘ de Marina Moreno c.1974', 'Esquina de la calle de Agustina Simв”ңв”Ӯn con el paseo de Marina Moreno de Zaragoza. En el centro, un trolebв”ңв•‘s de dos pisos de la lв”ңВЎnea Ciudad Jardв”ңВЎn. Fuente: dp-foto.blogspot.com', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.64791800, -0.88388500, '0101000020E610000046990D32C948ECBFAF3E1EFAEED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20515487658.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20515487658.webp', 'https://www.flickr.com/photos/zaragozaantigua/20515487658/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25995, 'Miraflores 1961', 'Una mirada en altura al sureste de la ciudad, con el Camino de las Torres en primer tв”ңВ®rmino (hasta los tejados de teja de las inmediatas parcelas), los campos de herbв”ңГӯceas de Miraflores, las tapias del convento-colegio de los PP Agustinos, el Colegio de San Josв”ңВ® de Calasanz, las parcelas de la calle Lobera, Tenor Fleta en progresiв”ңв”Ӯn constructiva, la fв”ңГӯbrica de "La Zaragozana" (con su chimenea aв”ңв•‘n en pie) junto al antiguo Camino de las Alcachoferas... La imagen estв”ңГӯ capturada desde la terraza del nв”¬в•‘ 46 de la calle General Sueiro. El vecino nв”¬в•‘ 54 recayente al Camino de las Torres estв”ңГӯ en construcciв”ңв”Ӯn. Fuente visual: www.facebook.com/photo.php?fbid=10205721956156450&set...', 1961, 1961, 1961, 'Anos 60', 'CENTRO', 41.64227500, -0.87994600, '0101000020E61000005DDF87838428ECBFEA04341136D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20454695486.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20454695486.webp', 'https://www.flickr.com/photos/zaragozaantigua/20454695486/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26047, 'Vista panorв”ңГӯmica c.1904', 'Postal panorв”ңГӯmica coloreada que muestra el arbolado curso del rв”ңВЎo Huerva, con las traseras de la iglesia de Santa Engracia. Al fondo, la torre del Pilar, la Seo, la Magdalena, San Carlos y San Miguel. Fuente: www.todocoleccion.net', 1904, 1904, 1904, 'Anos 1900', 'CENTRO', 41.64809200, -0.88222300, '0101000020E6100000A2ED98BA2B3BECBF4D66BCADF4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31682760194.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31682760194.webp', 'https://www.flickr.com/photos/zaragozaantigua/31682760194/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26062, 'Av. de Marina Moreno c.1963', 'Imagen capturada desde la altura del Edificio Elв”ңВЎseos y centrada en el arranque de la avenida de Marina Moreno. A la izquierda, interesante vista de las traseras de los hotelitos de la plaza de Aragв”ңв”Ӯn recayentes a la frondosa avenida, ya con el hueco dejado por el pionero derribo del edificio del antiguo Gobierno Civil. A la derecha, la mole del colegio del Salvador y la Residencia Universitaria de los PP. Jesuitas. En el centro de la escena, la iglesia de Santa Engracia y el convento de las Religiosas de Marв”ңВЎa Inmaculada, tras el que destaca el cartelв”ңв”Ӯn del Gran Hotel. Hacia el fondo, y de izquierda a derecha, emergen diversas torres de la ciudad: la de la Seo, de la Caja de Previsiв”ңв”Ӯn Social, las de San Pedro Nolasco, de Santa Marв”ңВЎa Magdalena, y de San Carlos Borromeo.', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.64693500, -0.88461200, '0101000020E6100000DAC534D3BD4EECBFA2D11DC4CED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49080041646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49080041646.webp', 'https://www.flickr.com/photos/zaragozaantigua/49080041646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21316, 'Pabellв”ңв”Ӯn Mariano 1908', 'Dibujo del "Pabellв”ңв”Ӯn Mariano a vista de pв”ңГӯjaro" incluido en la serie de postales editadas por la revista religiosa "Anales del Pilar". En este efв”ңВЎmero edificio, proyectado por el arquitecto Josв”ңВ® Marв”ңВЎa Pericв”ңГӯs Morros dentro del recinto de la Exposiciв”ңв”Ӯn Hispano-Francesa de 1908, tuvo lugar la denominada "Exposiciв”ңв”Ӯn Mariana Universal de Zaragoza", que incluв”ңВЎa una antropolв”ңв”Ӯgica selecciв”ңв”Ӯn de objetos relacionados con el culto mariano y artesanв”ңВЎas asociadas a sus ritos y ceremoniales. En esta idealizada escena "a vista de pв”ңГӯjaro", el Pabellв”ңв”Ӯn Mariano aparece flanqueado a la izquierda por los trazos esbozados del Pabellв”ңв”Ӯn de Tracciв”ңв”Ӯn, y a la derecha por el Palacio de Bellas Artes. Al fondo, el Pabellв”ңв”Ӯn de Alimentaciв”ңв”Ӯn. Fuente visual: Litografв”ңВЎa Marв”ңВЎn, en www.delcampe.net/', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64772100, -0.87886200, '0101000020E6100000124F7633A31FECBF59F78F85E8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40224270183.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40224270183.webp', 'https://www.flickr.com/photos/zaragozaantigua/40224270183/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21334, 'P.в”¬в•‘ de la Mina 1903', 'Imagen capturada en el antiguo paseo de Ronda, nuevo de la Mina y calle del Asalto (en el tramo comprendido entre la Puerta Quemada y la Puerta del Sol), con motivo del ferial de ganados de abasto y caballerв”ңВЎas aquв”ңВЎ instalado en octubre al hilo de las Fiestas del Pilar. Centra la escena un puesto donde se anuncia "carruajes venta- nuevos y usados- ay mas donde elejir".', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.64855200, -0.87727500, '0101000020E610000018265305A312ECBFB1E07EC003D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51700381115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51700381115.webp', 'https://www.flickr.com/photos/zaragozaantigua/51700381115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21336, 'Palacio de Museos 1908', '"Palacio de Museos", pabellв”ңв”Ӯn permanente de la Exposiciв”ңв”Ӯn Hispano-Francesa de 1908 en la huerta de Santa Engracia, segв”ңв•‘n proyecto de Ricardo Magdalena y Julio Bravo. Desde su apertura en 1911, funciona como museo de la ciudad.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64820800, -0.87860500, '0101000020E61000003D44A33B881DECBFB680D07AF8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53757128962.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53757128962.webp', 'https://www.flickr.com/photos/zaragozaantigua/53757128962/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21338, 'Interior Pabellв”ңв”Ӯn Mariano 1908', 'Interior del Pabellв”ңв”Ӯn Mariano en la Exposiciв”ңв”Ӯn Hispano-Francesa de 1908, huerta de Santa Engracia.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64780700, -0.87964600, '0101000020E6100000B7D4415E0F26ECBF588FFB56EBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53816044442.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53816044442.webp', 'https://www.flickr.com/photos/zaragozaantigua/53816044442/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
